@page "/calendar"
@using sv_101bf5f10d4d469f97b3c249178575ea
@inject ICalendarService CalendarService
@rendermode InteractiveServer

<PageTitle>Team Calendar</PageTitle>

<div class="calendar-container">
    <div class="calendar-main">
        <!-- Month Navigation Bar -->
        <div class="month-nav">
            <button class="btn btn-outline" @onclick="PreviousMonth">Previous</button>
            <button class="btn btn-outline" @onclick="GoToToday">Today</button>
            <h2 class="month-label">@currentDate.ToString("MMMM yyyy")</h2>
            <button class="btn btn-outline" @onclick="NextMonth">Next</button>
        </div>

        <!-- Team Member Filter -->
        <div class="team-filter">
            <button class="btn btn-sm" @onclick="ToggleSelectAll">
                @(allSelected ? "Deselect All" : "Select All")
            </button>
            @foreach (var member in teamMembers)
            {
                <label class="filter-checkbox">
                    <input type="checkbox" checked="@selectedMembers.Contains(member)"
                           @onchange="e => ToggleMember(member, (bool)e.Value!)" />
                    @member
                </label>
            }
        </div>

        <!-- Calendar Grid -->
        <div class="calendar-grid">
            <div class="day-header">Mon</div>
            <div class="day-header">Tue</div>
            <div class="day-header">Wed</div>
            <div class="day-header">Thu</div>
            <div class="day-header">Fri</div>
            <div class="day-header">Sat</div>
            <div class="day-header">Sun</div>

            @foreach (var day in calendarDays)
            {
                var dayCopy = day;
                <div class="day-cell @DayCellClass(day)" @onclick="() => SelectDay(dayCopy)">
                    <span class="day-number">@day.Day</span>
                    @if (day.Month == currentDate.Month)
                    {
                        var dayEvents = GetFilteredEventsForDay(day);
                        var dots = dayEvents.Take(3).ToList();
                        var extra = dayEvents.Count - 3;

                        @if (dots.Count > 0)
                        {
                            <div class="event-dots">
                                @foreach (var _ in dots)
                                {
                                    <span class="event-dot"></span>
                                }
                                @if (extra > 0)
                                {
                                    <span class="more-label">+@extra more</span>
                                }
                            </div>
                        }
                    }
                </div>
            }
        </div>
    </div>

    <!-- Day Detail Side Panel -->
    @if (selectedDay.HasValue)
    {
        <div class="day-panel">
            @if (!showNewEventForm)
            {
                <h3>@selectedDay.Value.ToString("dddd, MMMM d, yyyy")</h3>

                var dayEvents = GetFilteredEventsForDay(selectedDay.Value);
                @if (dayEvents.Count == 0)
                {
                    <p class="no-events">No events scheduled</p>
                }
                else
                {
                    <ul class="event-list">
                        @foreach (var evt in dayEvents)
                        {
                            <li class="event-item">
                                <div class="event-title">@evt.Title</div>
                                <div class="event-time">@FormatTime(evt.StartTime) &ndash; @FormatTime(evt.EndTime)</div>
                                <div class="event-attendees">@string.Join(", ", evt.Attendees)</div>
                                <button class="btn btn-danger btn-sm" @onclick="() => DeleteEvent(evt.Id)">Delete</button>
                            </li>
                        }
                    </ul>
                }

                <button class="btn btn-primary new-event-btn" @onclick="ShowNewEventForm">New Event</button>
            }
            else
            {
                <!-- New Event Form -->
                <h3>New Event</h3>
                <div class="event-form">
                    <label>
                        Title
                        <input type="text" @bind="newEventTitle" />
                    </label>
                    <label>
                        Date
                        <input type="date" @bind="newEventDate" />
                    </label>
                    <label>
                        Start Time
                        <input type="time" @bind="newEventStartTime" />
                    </label>
                    <label>
                        End Time
                        <input type="time" @bind="newEventEndTime" />
                    </label>
                    <fieldset>
                        <legend>Attendees</legend>
                        @foreach (var member in teamMembers)
                        {
                            <label class="filter-checkbox">
                                <input type="checkbox" checked="@newEventAttendees.Contains(member)"
                                       @onchange="e => ToggleNewEventAttendee(member, (bool)e.Value!)" />
                                @member
                            </label>
                        }
                    </fieldset>
                    <div class="form-buttons">
                        <button class="btn btn-primary" @onclick="SaveNewEvent">Save</button>
                        <button class="btn btn-outline" @onclick="CancelNewEvent">Cancel</button>
                    </div>
                </div>
            }
        </div>
    }
</div>

@code {
    private DateTime currentDate = DateTime.Today;
    private DateTime? selectedDay;
    private List<string> teamMembers = new();
    private HashSet<string> selectedMembers = new();
    private List<CalendarEvent> events = new();
    private List<DateTime> calendarDays = new();

    private bool showNewEventForm;
    private string newEventTitle = string.Empty;
    private DateTime newEventDate;
    private TimeSpan newEventStartTime = new(9, 0, 0);
    private TimeSpan newEventEndTime = new(10, 0, 0);
    private HashSet<string> newEventAttendees = new();

    private bool allSelected => teamMembers.Count > 0 && selectedMembers.Count == teamMembers.Count;

    protected override async Task OnInitializedAsync()
    {
        teamMembers = await CalendarService.GetTeamMembersAsync();
        selectedMembers = new HashSet<string>(teamMembers);
        await LoadMonth();
    }

    private async Task LoadMonth()
    {
        events = await CalendarService.GetEventsAsync(currentDate.Year, currentDate.Month);
        BuildCalendarDays();
    }

    private void BuildCalendarDays()
    {
        calendarDays = new List<DateTime>();
        var firstOfMonth = new DateTime(currentDate.Year, currentDate.Month, 1);
        int startOffset = ((int)firstOfMonth.DayOfWeek + 6) % 7; // Monday = 0
        var startDate = firstOfMonth.AddDays(-startOffset);

        for (int i = 0; i < 42; i++)
        {
            calendarDays.Add(startDate.AddDays(i));
        }
    }

    private List<CalendarEvent> GetFilteredEventsForDay(DateTime day)
    {
        return events
            .Where(e => e.Date.Date == day.Date && e.Attendees.Any(a => selectedMembers.Contains(a)))
            .ToList();
    }

    private string DayCellClass(DateTime day)
    {
        var classes = new List<string>();
        if (day.Month != currentDate.Month)
            classes.Add("outside-month");
        if (day.Date == DateTime.Today)
            classes.Add("today");
        if (selectedDay.HasValue && day.Date == selectedDay.Value.Date)
            classes.Add("selected");
        return string.Join(" ", classes);
    }

    private void SelectDay(DateTime day)
    {
        selectedDay = day;
        showNewEventForm = false;
    }

    private async Task PreviousMonth()
    {
        currentDate = currentDate.AddMonths(-1);
        await LoadMonth();
    }

    private async Task NextMonth()
    {
        currentDate = currentDate.AddMonths(1);
        await LoadMonth();
    }

    private async Task GoToToday()
    {
        currentDate = DateTime.Today;
        selectedDay = DateTime.Today;
        await LoadMonth();
    }

    private void ToggleMember(string member, bool isChecked)
    {
        if (isChecked)
            selectedMembers.Add(member);
        else
            selectedMembers.Remove(member);
    }

    private void ToggleSelectAll()
    {
        if (allSelected)
            selectedMembers.Clear();
        else
            selectedMembers = new HashSet<string>(teamMembers);
    }

    private async Task DeleteEvent(int eventId)
    {
        await CalendarService.DeleteEventAsync(eventId);
        await LoadMonth();
    }

    private void ShowNewEventForm()
    {
        showNewEventForm = true;
        newEventTitle = string.Empty;
        newEventDate = selectedDay ?? DateTime.Today;
        newEventStartTime = new TimeSpan(9, 0, 0);
        newEventEndTime = new TimeSpan(10, 0, 0);
        newEventAttendees = new HashSet<string>();
    }

    private void CancelNewEvent()
    {
        showNewEventForm = false;
    }

    private async Task SaveNewEvent()
    {
        if (string.IsNullOrWhiteSpace(newEventTitle))
            return;

        await CalendarService.CreateEventAsync(
            newEventTitle,
            newEventDate,
            newEventStartTime,
            newEventEndTime,
            newEventAttendees.ToList());

        showNewEventForm = false;
        currentDate = new DateTime(newEventDate.Year, newEventDate.Month, 1);
        await LoadMonth();
    }

    private void ToggleNewEventAttendee(string member, bool isChecked)
    {
        if (isChecked)
            newEventAttendees.Add(member);
        else
            newEventAttendees.Remove(member);
    }

    private string FormatTime(TimeSpan time)
    {
        var dt = DateTime.Today.Add(time);
        return dt.ToString("h:mm tt");
    }
}

.calendar-container {
    display: flex;
    gap: 1.5rem;
    padding: 1rem;
    max-width: 1200px;
    margin: 0 auto;
}

.calendar-main {
    flex: 1;
    min-width: 0;
}

/* Month Navigation */
.month-nav {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    margin-bottom: 1rem;
}

.month-label {
    flex: 1;
    text-align: center;
    margin: 0;
    font-size: 1.4rem;
}

/* Team Filter */
.team-filter {
    display: flex;
    flex-wrap: wrap;
    align-items: center;
    gap: 0.75rem;
    margin-bottom: 1rem;
    padding: 0.5rem;
    background: #f8f9fa;
    border-radius: 6px;
}

.filter-checkbox {
    display: flex;
    align-items: center;
    gap: 0.3rem;
    cursor: pointer;
    font-size: 0.9rem;
}

/* Calendar Grid */
.calendar-grid {
    display: grid;
    grid-template-columns: repeat(7, 1fr);
    gap: 1px;
    background: #dee2e6;
    border: 1px solid #dee2e6;
    border-radius: 6px;
    overflow: hidden;
}

.day-header {
    background: #495057;
    color: #fff;
    text-align: center;
    padding: 0.5rem;
    font-weight: 600;
    font-size: 0.85rem;
}

.day-cell {
    background: #fff;
    min-height: 80px;
    padding: 0.4rem;
    cursor: pointer;
    position: relative;
    transition: background 0.15s;
}

.day-cell:hover {
    background: #e9ecef;
}

.day-cell.outside-month {
    background: #f8f9fa;
    color: #adb5bd;
}

.day-cell.today {
    background: #e7f5ff;
    border: 2px solid #339af0;
}

.day-cell.selected {
    background: #d0ebff;
}

.day-number {
    font-weight: 600;
    font-size: 0.85rem;
}

.event-dots {
    display: flex;
    align-items: center;
    gap: 3px;
    margin-top: 0.3rem;
    flex-wrap: wrap;
}

.event-dot {
    width: 8px;
    height: 8px;
    border-radius: 50%;
    background: #339af0;
}

.more-label {
    font-size: 0.7rem;
    color: #868e96;
}

/* Day Panel */
.day-panel {
    width: 320px;
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 8px;
    padding: 1.25rem;
    align-self: flex-start;
    position: sticky;
    top: 1rem;
}

.day-panel h3 {
    margin: 0 0 1rem 0;
    font-size: 1.1rem;
}

.no-events {
    color: #868e96;
    font-style: italic;
}

.event-list {
    list-style: none;
    padding: 0;
    margin: 0 0 1rem 0;
}

.event-item {
    padding: 0.75rem;
    border: 1px solid #e9ecef;
    border-radius: 6px;
    margin-bottom: 0.5rem;
}

.event-title {
    font-weight: 600;
    margin-bottom: 0.25rem;
}

.event-time {
    font-size: 0.85rem;
    color: #495057;
}

.event-attendees {
    font-size: 0.8rem;
    color: #868e96;
    margin-bottom: 0.4rem;
}

.new-event-btn {
    width: 100%;
}

/* Event Form */
.event-form {
    display: flex;
    flex-direction: column;
    gap: 0.75rem;
}

.event-form label {
    display: flex;
    flex-direction: column;
    gap: 0.25rem;
    font-size: 0.9rem;
    font-weight: 500;
}

.event-form input[type="text"],
.event-form input[type="date"],
.event-form input[type="time"] {
    padding: 0.4rem 0.6rem;
    border: 1px solid #ced4da;
    border-radius: 4px;
    font-size: 0.9rem;
}

.event-form fieldset {
    border: 1px solid #dee2e6;
    border-radius: 4px;
    padding: 0.5rem;
}

.event-form legend {
    font-size: 0.85rem;
    font-weight: 500;
    padding: 0 0.3rem;
}

.form-buttons {
    display: flex;
    gap: 0.5rem;
}

/* Buttons */
.btn {
    padding: 0.4rem 0.9rem;
    border-radius: 4px;
    border: 1px solid transparent;
    cursor: pointer;
    font-size: 0.9rem;
    transition: background 0.15s;
}

.btn-outline {
    background: #fff;
    border-color: #ced4da;
    color: #495057;
}

.btn-outline:hover {
    background: #f1f3f5;
}

.btn-primary {
    background: #339af0;
    color: #fff;
}

.btn-primary:hover {
    background: #228be6;
}

.btn-danger {
    background: #fa5252;
    color: #fff;
}

.btn-danger:hover {
    background: #e03131;
}

.btn-sm {
    padding: 0.25rem 0.6rem;
    font-size: 0.8rem;
}

