.calendar-container {
    display: flex;
    gap: 1.5rem;
    padding: 1rem;
    max-width: 1200px;
    margin: 0 auto;
}

.calendar-main {
    flex: 1;
    min-width: 0;
}

/* Month Navigation */
.month-nav {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    margin-bottom: 1rem;
}

.month-label {
    flex: 1;
    text-align: center;
    margin: 0;
    font-size: 1.4rem;
}

/* Team Filter */
.team-filter {
    display: flex;
    flex-wrap: wrap;
