.calendar-grid {
    display: grid;
    grid-template-columns: repeat(7, 1fr);
    gap: 1px;
    background: #dee2e6;
    border: 1px solid #dee2e6;
    border-radius: 6px;
    overflow: hidden;
}

.day-header {
    background: #495057;
    color: #fff;
    text-align: center;
    padding: 0.5rem;
    font-weight: 600;
    font-size: 0.85rem;
}

.day-cell {
    background: #fff;
    min-height: 80px;
    padding: 0.4rem;
    cursor: pointer;
    position: relative;
    transition: background 0.15s;
}

.day-cell:hover {
    background: #e9ecef;
}

.day-cell.outside-month {
    background: #f8f9fa;
    color: #adb5bd;
}

.day-cell.today {
    background: #e7f5ff;
    border: 2px solid #339af0;
}

.day-cell.selected {
    background: #d0ebff;
}

.day-number {
    font-weight: 600;
    font-size: 0.85rem;
}

.event-dots {
    display: flex;
    align-items: center;
    gap: 3px;
    margin-top: 0.3rem;
    flex-wrap: wrap;
}

.event-dot {
    width: 8px;
    height: 8px;
    border-radius: 50%;
    background: #339af0;
}

.more-label {
    font-size: 0.7rem;
    color: #868e96;
}

/* Day Panel */
.day-panel {
    width: 320px;
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 8px;
    padding: 1.25rem;
    align-self: flex-start;
    position: sticky;
    top: 1rem;
}

.day-panel h3 {
    margin: 0 0 1rem 0;
    font-size: 1.1rem;
}

.no-events {
    color: #868e96;
    font-style: italic;
}

.event-list {
    list-style: none;
    padding: 0;
    margin: 0 0 1rem 0;
}

.event-item {
    padding: 0.75rem;
    border: 1px solid #e9ecef;
    border-radius: 6px;
    margin-bottom: 0.5rem;
}

.event-title {
    font-weight: 600;
    margin-bottom: 0.25rem;
}

.event-time {
    font-size: 0.85rem;
    color: #495057;
}

.event-attendees {
    font-size: 0.8rem;
    color: #868e96;
    margin-bottom: 0.4rem;
}

.new-event-btn {
    width: 100%;
}

/* Event Form */
.event-form {
    display: flex;
    flex-direction: column;
    gap: 0.75rem;
}

.event-form label {
    display: flex;
    flex-direction: column;
    gap: 0.25rem;
    font-size: 0.9rem;
    font-weight: 500;
}

.event-form input[type="text"],
.event-form input[type="date"],
.event-form input[type="time"] {
    padding: 0.4rem 0.6rem;
    border: 1px solid #ced4da;
    border-radius: 4px;
    font-size: 0.9rem;
}

.event-form fieldset {
    border: 1px solid #dee2e6;
    border-radius: 4px;
    padding: 0.5rem;
}

.event-form legend {
    font-size: 0.85rem;
    font-weight: 500;
    padding: 0 0.3rem;
}

.form-buttons {
    display: flex;
    gap: 0.5rem;
}

/* Buttons */
.btn {
    padding: 0.4rem 0.9rem;
    border-radius: 4px;
    border: 1px solid transparent;
    cursor: pointer;
    font-size: 0.9rem;
    transition: background 0.15s;
}

.btn-outline {
    background: #fff;
    border-color: #ced4da;
    color: #495057;
}

.btn-outline:hover {
